import { FilterQuery } from 'mongoose';
import { EvaluationReport } from '../models/evaluation-report.model';
import {
  IEvaluationReport,
  IEvaluationReportDocument,
} from '../interfaces/evaluation-report.interface';

/**
 * Repository for the `evaluationReports` collection.
 *
 * Phase 1 surface area: read-only listing + per-student lookup. The
 * write path (`dbStore.addEvaluationReport` in legacy `index.ts:765`)
 * continues to write the same collection directly so the new Reports
 * panel sees reports generated by either the legacy diagnostic pipeline
 * or any future modular writer.
 *
 * Response convention (matches Student module):
 *   - All reads return plain JS objects via `.lean().exec()` so the
 *     controller can JSON-serialize them directly without Mongoose
 *     document wrappers.
 *   - `findAll` returns a sorted list (newest first by timestamp) so the
 *     frontend can render rows in presentation order without extra sort.
 */
export class EvaluationReportRepository {
  /**
   * List evaluation reports matching the supplied filter.
   *
   * Filters are business-id strings only (`studentId`, `schoolId`,
   * `worksheetId`) тАФ same convention as the Student and Class modules.
   * No business-id coercion; seeded `studentId` strings already use the
   * canonical `s_<school>_<class>_<roll>` shape.
   *
   * The `schoolId` filter is forwarded as a `studentId` regex match via
   * a service-side lookup if needed. Here we accept it as a literal
   * filter too тАФ if the seeded collection ever records the school on
   * each report, the controller / service would resolve it; for now the
   * service applies the school-scope via a `students` cross-check.
   */
  async findAll(
    filter?: FilterQuery<IEvaluationReportDocument>
  ): Promise<IEvaluationReport[]> {
    return EvaluationReport.find(filter || {})
      .sort({ timestamp: -1 })
      .lean()
      .exec() as unknown as Promise<IEvaluationReport[]>;
  }

  /**
   * Convenience: the per-student history lookup used by the legacy
   * `index.ts:1395 /api/evaluation/:studentId/history` handler. Returns
   * `[]` when the student has no reports.
   */
  async findByStudentId(studentId: string): Promise<IEvaluationReport[]> {
    return EvaluationReport.find({ studentId })
      .sort({ timestamp: -1 })
      .lean()
      .exec() as unknown as Promise<IEvaluationReport[]>;
  }
}

/**
 * Singleton. The repository only touches the Mongoose model directly тАФ
 * it has no process-level state, so a singleton is safe.
 */
export const evaluationReportRepository = new EvaluationReportRepository();